import{_ as t,o as i,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"48. Staffing Flexibility Dhsv","description":"","frontmatter":{"title":"48. Staffing Flexibility Dhsv","eba":"Health Allied & Managers Admin 2021-2025","topics":["preliminary","classifications","staffing"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/workplace-rights/48-staffing-flexibility-dhsv.md","filePath":"ebas/has-managers-admin/health-allied-services/workplace-rights/48-staffing-flexibility-dhsv.md"}'),n={name:"ebas/has-managers-admin/health-allied-services/workplace-rights/48-staffing-flexibility-dhsv.md"};function r(l,e,o,h,f,c){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_48-staffing-flexibility-dhsv" tabindex="-1">48. Staffing Flexibility Dhsv <a class="header-anchor" href="#_48-staffing-flexibility-dhsv" aria-label="Permalink to &quot;48. Staffing Flexibility Dhsv&quot;">​</a></h1><p>This clause only applies to Dental Assistants employed by DHSV.</p><p><strong>48.1</strong> The Employer may direct an Employee to carry out duties that are incidental and peripheral to the work normally performed, where those duties are within the Employee’s skill, competence and training and are consistent with the classification structure.</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>48.2</strong> The parties recognise the optimum staffing arrangement is for a Dental Assistant to work with a dedicated Dental Therapist whilst performing clinical duties. The Employer will continue to work towards implementing the optimum staffing arrangement.</p><p><strong>48.3</strong> There will be circumstances (for example short term unplanned absences) that necessitate a Dental Assistant working temporarily in a two-Dental Therapist-to- one-Dental Assistant staffing configuration. In such circumstances, Employees will be flexible in relation to staffing arrangements.</p>',6)])])}const d=t(n,[["render",r]]);export{m as __pageData,d as default};
